        let c = create_task(conn, &epic_id, &project_id, "C", None, None).await.unwrap();

        // A -> B -> C is a valid chain.
        link_dependency(conn, &a.id, &b.id).await.unwrap();
        link_dependency(conn, &b.id, &c.id).await.unwrap();

